# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from prometheus_client import Collector, start_http_server, GaugeMetricFamily
from flask import Flask, request

app = Flask(__name__)
metrics = {}

def register_metric(user_id, path):
    if user_id not in metrics:
        metrics[user_id] = {}
    if path not in metrics[user_id]:
        metrics[user_id][path] = Collector(
            GaugeMetricFamily('request_count', 'Number of requests per user-path combination.', labels=['user_id', 'session_id', 'path']).add_metric([user_id, request.cookies.get('session_id'), path])
        )
        app.prometheus_metrics.register(metrics[user_id][path])

@app.route('/<path:path>')
def handle_request(path):
    user_id = request.args.get('user_id', 'unknown')
    metrics[user_id][path].remove_sample()  # update the metric
    return f'Request handled for user {user_id} at path {path}'

if __name__ == "__main__":
    start_http_server(8000)
    app.run(debug=True)